export const glossary: GlossaryItem[] = [
  { term: 'ADR', def: 'Architecture Decision Record. A short document capturing a decision, its context, alternatives, and consequences.' },
  { term: 'ABAC', def: 'Attribute-Based Access Control. Access based on user/resource attributes rather than roles.' },
  { term: 'Agentic AI', def: 'AI systems that can take actions autonomously — calling tools, making decisions, escalating to humans.' },
  { term: 'Backoff', def: 'Retry strategy that increases wait time between retries to avoid overwhelming a service.' },
  { term: 'Blue/Green', def: 'Deployment strategy with two identical environments; switch traffic from one to the other.' },
  { term: 'Canary', def: 'Deployment strategy that releases to a small subset of users first to detect issues.' },
  { term: 'Circuit Breaker', def: 'Pattern that stops calling a failing service to prevent cascading failures.' },
  { term: 'CQRS', def: 'Command Query Responsibility Segregation. Separate read and write models for performance.' },
  { term: 'CSM', def: 'Cognitive Systems Management. Four-pillar framework underlying the HAIEC platform — bridges AI strategy, technical execution, and governance. Pillars: Strategic Alignment, Technical Implementation, Governance & Risk, Operational Excellence.' },
  { term: 'CSR', def: 'Client-Side Rendering. Browser renders the page using JavaScript.' },
  { term: 'DLQ', def: 'Dead Letter Queue. Queue for messages that failed processing and need manual intervention.' },
  { term: 'DDD', def: 'Domain-Driven Design. Modeling approach centered on business domain and invariants.' },
  { term: 'Embedding', def: 'Vector representation of text/data used for semantic search and retrieval in AI systems.' },
  { term: 'Evaluation Pipeline', def: 'Automated testing framework for AI outputs — checking quality, accuracy, bias, and safety.' },
  { term: 'Feature Flag', def: 'Toggle that enables/disables features without deploying new code.' },
  { term: 'Guardrails', def: 'Safety checks on AI inputs and outputs — content filtering, prompt injection defense, output validation.' },
  { term: 'Hallucination', def: 'AI generates plausible but incorrect or fabricated information.' },
  { term: 'Idempotency', def: 'Property where executing the same operation multiple times has the same effect as executing it once.' },
  { term: 'ISR', def: 'Incremental Static Regeneration. Next.js feature that updates static pages at runtime.' },
  { term: 'LLM-as-Judge', def: "Using a language model to evaluate the quality of another model's outputs." },
  { term: 'MoSCoW', def: "Prioritization method: Must-have, Should-have, Could-have, Won't-have." },
  { term: 'One-way door', def: 'A decision that is expensive or impossible to reverse (e.g., schema migration, domain model).' },
  { term: 'Prompt Injection', def: 'Attack where malicious instructions are embedded in input to manipulate AI behavior.' },
  { term: 'RACI', def: 'Responsibility assignment matrix: Responsible, Accountable, Consulted, Informed.' },
  { term: 'RAG', def: 'Retrieval-Augmented Generation. AI retrieves relevant documents before generating a response.' },
  { term: 'RBAC', def: 'Role-Based Access Control. Access permissions assigned to roles, not individuals.' },
  { term: 'RLS', def: 'Row-Level Security. Database-level policy that restricts which rows a user can access.' },
  { term: 'SAST', def: 'Static Application Security Testing. Automated security analysis of source code.' },
  { term: 'SLO', def: 'Service Level Objective. Target metric for system reliability (e.g., 99.9% uptime).' },
  { term: 'SSR', def: 'Server-Side Rendering. HTML is generated on the server and sent to the browser.' },
  { term: 'TCO', def: 'Total Cost of Ownership. Full cost including licensing, hosting, maintenance, and operations.' },
  { term: 'Two-way door', def: 'A decision that can be reversed relatively easily (e.g., caching strategy, UI framework).' },
  { term: 'Vector DB', def: 'Database optimized for storing and searching vector embeddings (e.g., Pinecone, pgvector).' },
]

