export const scenarioMap: Record<string, (l: Layer) => boolean> = {
  webapp: (l) => l.g !== 'E',
  aiproduct: () => true,
  aitools: () => true,
  audit: (l) => [22, 25, 18, 10, 8].includes(l.id),
  pilot: (l) => [15, 16, 22, 25].includes(l.id),
}

export const filterDefs: { key: keyof { group: string[]; crit: string[]; phase: string[]; status: string[]; appl: string[]; csmPillar: string[] }; label: string; options: { val: string; label: string }[] }[] = [
  { key: 'group', label: 'Group', options: groups.map(g => ({ val: g.id, label: g.name })) },
  { key: 'crit', label: 'Criticality', options: [{ val: 'Critical', label: 'Critical' }, { val: 'Important', label: 'Important' }, { val: 'Standard', label: 'Standard' }] },
  { key: 'phase', label: 'Phase', options: [{ val: 'Discovery', label: 'Discovery' }, { val: 'Design', label: 'Design' }, { val: 'Build', label: 'Build' }, { val: 'Launch', label: 'Launch' }, { val: 'Operate', label: 'Operate' }] },
  { key: 'status', label: 'Status', options: [{ val: 'Not Started', label: 'Not Started' }, { val: 'In Discussion', label: 'In Discussion' }, { val: 'Decided', label: 'Decided' }, { val: 'Blocked', label: 'Blocked' }] },
  { key: 'appl', label: 'Applicability', options: [{ val: 'Always', label: 'Always' }, { val: 'Conditional', label: 'Conditional' }] },
  { key: 'csmPillar', label: 'CSM Pillar', options: csmPillars.map(p => ({ val: p.id, label: p.name })) },
]
